INSERT INTO creators (id,display_name,slug,instagram_handle,tiktok_handle,instagram_followers,tiktok_followers,bio,avatar_url,tier,specialties,areas_covered,rate_range_low,rate_range_high,is_founding_creator,is_active,platform_fee_rate,content_rights_status) VALUES ('c484f03b-8621-540e-832d-1437f40b0ece','The Hungry Coyote','the-hungry-coyote','@thehungrycoyote','@thehungrycoyote',23000,42000,'Phoenix food from the west side to the east side. BBQ, street tacos, and dive bars. The spots your GPS doesn''t know about.','https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200&h=200&fit=crop&crop=face','micro','{"BBQ/Comfort","Mexican","Hidden Gems"}','{"Gilbert","Chandler","Peoria","Cave Creek"}',200,500,TRUE,TRUE,0.05,'granted');
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('3600f50d-ec59-56aa-9e86-9c71d6b2a5e0','aebfc1d8-aaae-5c35-b533-9757904b76b5','39d6a76c-a0af-56bb-93ff-740046b527c1','video','https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=640&h=800&fit=crop',12,'0.8','instagram','The yellowtail tostada at Marisco Boys is unreal. Fresh fish piled high, black garlic aioli, crispy tortillas. This is date night seafood done RIGHT. 🐟🔥','{"Mexican","Seafood"}','{"Date Night","Trendy / New"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('bf564fca-7a03-5f9a-bfac-2a56f53ff4d2','be79e48e-8038-539e-87e8-ecf3f64e5cf0','0c9ed30c-776b-5ee4-8f49-5620b18f09b2','video','https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=640&h=800&fit=crop',15,'0.8','instagram','Pretty Penny on Roosevelt Row just set a new standard. Welcome bubbles, housemade pasta, and they serve caviar AT COST. The ricotta cavatelli had me speechless.','{"Italian"}','{"Splurge-Worthy","Date Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('191504ce-4f2a-565e-8090-0c4de29ba3a4','aebfc1d8-aaae-5c35-b533-9757904b76b5','e379a363-6762-5045-916c-ac0081fff350','video','https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=640&h=800&fit=crop',10,'0.8','tiktok','Filthy Animal in Tempe has a STUFFED JAGUAR in the dining room. But the real star is this wagyu burger with truffle fries. Decor is insane, food matches. Mill Ave just leveled up.','{"American"}','{"Trendy / New","Group Dinner"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('79dedc88-bb7d-5b77-966b-debe19024f3e','be79e48e-8038-539e-87e8-ecf3f64e5cf0','c11740cd-352a-5243-a1b3-46ba428209e5','photo','https://images.unsplash.com/photo-1585937421612-70a008356fbe?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1585937421612-70a008356fbe?w=640&h=800&fit=crop',0,'0.8','instagram','Indibar replaced Rancho Pinot and it''s STUNNING. Kerala-inspired branzino wrapped in banana leaf, opened tableside. Butter chicken that redefines the category. This is elevated Indian dining done with soul.','{"Asian"}','{"Splurge-Worthy","Date Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('41a49c43-ddf8-59b4-9cef-477e254b955b','fe4d5021-5061-5c4c-9c42-bc3d8aa4f75e','c8731cf1-48c2-568b-b4fe-cd058c0299e5','video','https://images.unsplash.com/photo-1473093295043-cdd812d0e601?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1473093295043-cdd812d0e601?w=640&h=800&fit=crop',14,'0.8','instagram','Bar Capri is hiding in a Tempe strip mall and it''s one of the best Italian spots in the Valley. Lasagna is THICK. Tiramisu is the real deal. Green walls, gold candelabras — feels like a secret.','{"Italian"}','{"Hidden Gem","Date Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('00fa487c-7994-57e9-b238-e2a4427ab257','aebfc1d8-aaae-5c35-b533-9757904b76b5','67d31a19-05f2-53f7-8311-7e9f66bf6d82','video','https://images.unsplash.com/photo-1551024709-8f23befc6f87?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1551024709-8f23befc6f87?w=640&h=800&fit=crop',8,'0.8','tiktok','The Spam Folder cocktail at Liquor Pig is going VIRAL and honestly? It lives up to the hype. Old Town Scottsdale''s wildest new bar. Go.','{"American"}','{"Happy Hour","Late Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('f292097f-f669-5c99-aaff-21a5bdf00477','be79e48e-8038-539e-87e8-ecf3f64e5cf0','a05ec10e-2378-56cc-b764-d09f502e3814','video','https://images.unsplash.com/photo-1544025162-d76694265947?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1544025162-d76694265947?w=640&h=800&fit=crop',13,'0.8','instagram','The Ends in Old Town is giving Anthony Bourdain energy. 8-bone rack of lamb for the table? Yes. Handmade pasta? Perfect. This is Scottsdale dining with actual soul.','{"American","Italian"}','{"Splurge-Worthy","Group Dinner"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('3a40926c-c6dc-5cc9-89dd-e65f6e8ea758','be79e48e-8038-539e-87e8-ecf3f64e5cf0','f1e011c6-e31c-53dd-8f77-885b0645820b','photo','https://images.unsplash.com/photo-1482049016688-2d3e1b311543?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1482049016688-2d3e1b311543?w=640&h=800&fit=crop',0,'0.8','instagram','Andreoli Italian Grocer: burrata made FROM SCRATCH, paninis stacked with proper Italian meats, and a dessert case that will ruin your diet. 50 visits in and I''m still discovering new things.','{"Italian"}','{"Hidden Gem","Solo-Friendly"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('40d419fc-34cf-582b-a16a-01d199e08a88','aebfc1d8-aaae-5c35-b533-9757904b76b5','f86385c1-81d7-50d2-b984-4f9a95071f44','video','https://images.unsplash.com/photo-1559339352-11d035aa65de?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1559339352-11d035aa65de?w=640&h=800&fit=crop',11,'0.8','instagram','15 years and Citizen Public House still has the best chopped salad in Scottsdale. The patio at sunset? Unmatched. If you haven''t been, what are you doing.','{"American"}','{"Happy Hour","Patio"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('44251b45-772b-5eff-b095-c4c2615bd095','fe4d5021-5061-5c4c-9c42-bc3d8aa4f75e','1aa764d0-0c40-56d4-97c1-c31293286689','video','https://images.unsplash.com/photo-1551504734-5ee1c4a1479b?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1551504734-5ee1c4a1479b?w=640&h=800&fit=crop',9,'0.8','tiktok','Taco Boys birria tacos. $3 each. Consomé on the side. This is the real deal Phoenix street food and I will not apologize for eating four of them.','{"Mexican"}','{"Quick Bite","Solo-Friendly"}','organic',CURRENT_DATE,TRUE);
