INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('f10ef43e-2a9c-578e-af87-4103fe9023c6','fe4d5021-5061-5c4c-9c42-bc3d8aa4f75e','aa58ddff-afd7-595e-9db5-5f71d7802e78','photo','https://images.unsplash.com/photo-1513104890138-7c749659a591?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1513104890138-7c749659a591?w=640&h=800&fit=crop',0,'0.8','instagram','Spinato''s has been the answer to ''best pizza in AZ'' since 1974 and I''m not about to argue. The Valentina with Calabrian chile and local honey? Phoenix royalty. 🍕👑','{"Pizza"}','{"Family"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('17fda3cf-f7a5-555d-af0f-15cfa000455e','be79e48e-8038-539e-87e8-ecf3f64e5cf0','7260df7e-f96b-59b6-8b1e-d1a56acc6fb4','video','https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=640&h=800&fit=crop',14,'0.8','instagram','The Guest House at Scottsdale Quarter is giving main character energy. Warm lighting, lush greenery, cocktails that are almost too pretty to drink. Almost. New spot, already a favorite.','{"American"}','{"Trendy / New","Date Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('697bd8ec-80c6-5931-be9c-00c08862cac9','0114e984-c26c-5ef0-abcd-61724f9e0190','1752c71b-93a4-5d92-b001-d9aace882c4b','video','https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=640&h=800&fit=crop',10,'0.8','tiktok','Prep & Pastry brunch is the move. Churro waffle with dulce de leche? I''m weak. Patio seating on a Saturday morning in Scottsdale hits different.','{"Brunch"}','{"Brunch","Patio"}','organic',CURRENT_DATE,TRUE);
