INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('d717cb18-288f-5322-b60e-d65fff2e9163','c484f03b-8621-540e-832d-1437f40b0ece','2631a430-3112-5001-8955-9754da4d7401','video','https://images.unsplash.com/photo-1529193591184-b1d58069ecdd?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1529193591184-b1d58069ecdd?w=640&h=800&fit=crop',11,'0.8','tiktok','Little Miss BBQ brisket is the hill I will die on. Get there early — line wraps around the building by 11:30. They close when they sell out. Worth. Every. Minute. 🥩💨','{"BBQ/Comfort"}','{"Hidden Gem"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('cb31656d-74b4-558e-b31d-c6473dfdbfe8','c484f03b-8621-540e-832d-1437f40b0ece','9b8c3da4-851d-539b-ac64-26af2288dda6','video','https://images.unsplash.com/photo-1558030006-450675393462?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1558030006-450675393462?w=640&h=800&fit=crop',13,'0.8','instagram','Tonto Bar & Grill in Cave Creek is the kind of place that makes you forget you''re 30 min from downtown. Mesquite-grilled everything, patio under the stars, cowboy energy. Drive is worth it.','{"American","BBQ/Comfort"}','{"Patio","Hidden Gem"}','organic',CURRENT_DATE,TRUE);
