INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('1eff1ebb-4d6c-5898-854b-a1d862c89a3a','be79e48e-8038-539e-87e8-ecf3f64e5cf0','56c3489f-9257-55b9-8195-cc142a46b2d0','video','https://images.unsplash.com/photo-1559339352-11d035aa65de?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1559339352-11d035aa65de?w=640&h=800&fit=crop',15,'0.8','instagram','Catch just opened at Scottsdale Fashion Square and it''s giving LA energy. Sushi platter for two, wagyu tartare, and a cocktail menu that doesn''t miss. If you''re celebrating, this is the spot.','{"Seafood","American"}','{"Splurge-Worthy","Date Night"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('00124ef2-1282-5c82-8c28-f628c726ea3e','0114e984-c26c-5ef0-abcd-61724f9e0190','7fea93af-2ccc-52ae-a472-fdb8eaba85dc','video','https://images.unsplash.com/photo-1533089860892-a7c6f0a88666?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1533089860892-a7c6f0a88666?w=640&h=800&fit=crop',10,'0.8','tiktok','Hash Kitchen''s build-your-own bloody mary bar is CHAOS in the best way. Bacon strips, shrimp, candy, pickles — all hanging off your glass. Bring your friends. It''s a whole activity.','{"Brunch"}','{"Brunch","Group Dinner"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('aaa84760-7285-544a-b704-913df5260d69','aebfc1d8-aaae-5c35-b533-9757904b76b5','a32fe463-8fb9-5168-9c86-7d97cba1aff7','photo','https://images.unsplash.com/photo-1510812431401-41d2bd2722f3?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1510812431401-41d2bd2722f3?w=640&h=800&fit=crop',0,'0.8','instagram','Postino $5 pitchers of wine til 5pm is the best happy hour deal in Phoenix, fight me. Bruschetta board + a pitcher on the Arcadia patio. This is peak.','{"American","Italian"}','{"Happy Hour","Patio"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('1c15c188-4dde-525d-b8c0-a0b803e6d99a','0114e984-c26c-5ef0-abcd-61724f9e0190','4b7e9b49-0731-5f17-9f38-8e02b3a20b33','photo','https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=640&h=800&fit=crop',0,'0.8','instagram','Berdena''s is proof that healthy food doesn''t have to be boring. Grain bowl with chimichurri, pickled onions, and a perfect poached egg. The patio is tiny and perfect.','{"Healthy"}','{"Brunch","Solo-Friendly"}','organic',CURRENT_DATE,TRUE);
INSERT INTO content (id,creator_id,restaurant_id,content_type,media_url,thumbnail_url,duration_seconds,aspect_ratio,original_platform,caption,cuisine_tags,vibe_tags,sponsorship_status,publish_date,is_active) VALUES ('853343a6-878c-5acf-9dd4-0f001eccfda7','be79e48e-8038-539e-87e8-ecf3f64e5cf0','de01e36f-e4be-5aa6-9604-ae75c2c176db','video','https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=640&h=800&fit=crop','https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=640&h=800&fit=crop',12,'0.8','instagram','Mora Italian''s cacio e pepe is the dish I judge all other pasta by. Simple, perfect, and served in a space that feels like a love letter to Italian cooking. Top 5 dinner spot in Phoenix.','{"Italian"}','{"Date Night","Splurge-Worthy"}','organic',CURRENT_DATE,TRUE);
